// Parse Twilio WhatsApp webhook
const body = $input.first().json;

const from = body.From || '';
const to = body.To || '';
const messageBody = body.Body || '';
const messageSid = body.MessageSid || '';

// Extract phone number (strip 'whatsapp:' prefix)
const phone = from.replace('whatsapp:', '');

return {
  json: {
    phone,
    message: messageBody.trim(),
    messageSid,
    timestamp: new Date().toISOString()
  }
};

// Extract AI response
const response = $input.first().json;

let replyText = '';

if (typeof response === 'string') {
  replyText = response;
} else if (response.reply) {
  replyText = response.reply;
} else if (response.text) {
  replyText = response.text;
} else {
  replyText = $env.DEFAULT_REPLY || 'Thanks! A team member will respond shortly.';
}

// Trim to WhatsApp limit (4096 chars)
if (replyText.length > 4096) {
  replyText = replyText.substring(0, 4090) + '...';
}

return {
  json: {
    reply: replyText,
    original: response
  }
};
